function u(e){if(!e)return"";const r=new Date(e);return Number.isNaN(r.getTime())?e:r.toLocaleDateString("en-IN",{day:"numeric",month:"short",year:"numeric"})}function a(e){if(!e)return"0";const r=Number(e);return Number.isNaN(r)?e:r>=1e6?`${(r/1e6).toFixed(1)}M`:r>=1e3?`${(r/1e3).toFixed(1)}K`:String(r)}function s(e){if(!e)return"";const r=Date.now(),o=new Date(e).getTime();if(Number.isNaN(o))return e;const f=r-o,n=Math.floor(f/6e4);if(n<60)return`${n}m ago`;const t=Math.floor(n/60);if(t<24)return`${t}h ago`;const i=Math.floor(t/24);return i<30?`${i}d ago`:u(e)}export{u as a,a as f,s as t};
